public final class UtcDateTypeAdapter extends TypeAdapter<Date>{
private static void padInt(StringBuilder buffer, int value, int length) {
      String strValue = Integer.toString(value);
      for (int i = length - strValue.length(); i > 0; i--) {
          buffer.append('0');
      }
      buffer.append(strValue);
  }
private final TimeZone UTC_TIME_ZONE = TimeZone.getTimeZone("UTC");
private static final String GMT_ID = "GMT";
@Override public void write(JsonWriter out, Date date)
@Override public Date read(JsonReader in)
private static String format(Date date, boolean millis, TimeZone tz)
private static Date parse(String date, ParsePosition pos)
private static boolean checkOffset(String value, int offset, char expected)
private static int parseInt(String value, int beginIndex, int endIndex)
}
